SELECT trait_name, trait_ontology
FROM traits
ORDER BY trait_name ASC;

SELECT publication_title, year
FROM pgs_publications
ORDER BY year DESC;

SELECT creation_date, pgs_id
FROM polygenic_scores
ORDER BY creation_date DESC;

SELECT trait_reported_id, COUNT(*) AS num_scores
FROM polygenic_scores
GROUP BY trait_reported_id;

SELECT pgs_name, num_variants
FROM polygenic_scores
WHERE num_variants = (SELECT MAX(num_variants) FROM polygenic_scores);

SELECT trait_name
FROM traits
ORDER BY trait_name ASC;

SELECT pgs_id, num_variants
FROM polygenic_scores
ORDER BY num_variants ASC;

SELECT pgs_id
FROM polygenic_scores
ORDER BY pgs_id;

SELECT pgs_name
FROM polygenic_scores
WHERE last_updated = (
    SELECT MAX(last_updated)
    FROM polygenic_scores
);
